import React, { useEffect, useState } from 'react';
import api from '../utils/api';

export default function BorrowRequests() {
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('pending');
  const [msg, setMsg] = useState('');
  const [rejectModal, setRejectModal] = useState<any>(null);
  const [rejectReason, setRejectReason] = useState('');
  const [approveModal, setApproveModal] = useState<any>(null);
  const [dueDate, setDueDate] = useState('');

  const load = (status = filter) => {
    setLoading(true);
    api.get('/borrows/requests', { params: { status } })
      .then(r => { setRequests(r.data.data || []); setLoading(false); })
      .catch(() => setLoading(false));
  };

  useEffect(() => { load(filter); }, [filter]);

  // Default due date = 14 days
  const openApprove = (req: any) => {
    const d = new Date(); d.setDate(d.getDate() + 14);
    setDueDate(d.toISOString().split('T')[0]);
    setApproveModal(req);
  };

  const approve = async () => {
    try {
      await api.put(`/borrows/requests/${approveModal.id}/approve`, { due_date: dueDate });
      setMsg('✓ Request approved! Book issued.');
      setApproveModal(null);
      load();
    } catch (e: any) { setMsg('✕ ' + (e.response?.data?.message || 'Error')); }
    setTimeout(() => setMsg(''), 4000);
  };

  const reject = async () => {
    try {
      await api.put(`/borrows/requests/${rejectModal.id}/reject`, { reject_reason: rejectReason });
      setMsg('Request rejected.');
      setRejectModal(null);
      setRejectReason('');
      load();
    } catch { setMsg('Error occurred'); }
    setTimeout(() => setMsg(''), 3000);
  };

  const inp: React.CSSProperties = { width: '100%', padding: '9px 12px', border: '2px solid #e8e0d0', borderRadius: 9, fontSize: 13, fontFamily: 'inherit', outline: 'none', color: '#1a1a2e' };

  return (
    <div className="page-enter" style={{ padding: 32 }}>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 28, fontWeight: 700 }}>Borrow Requests</h1>
        <p style={{ color: '#9ca3af', fontSize: 13, marginTop: 4 }}>Review and approve member requests</p>
      </div>

      {msg && (
        <div style={{ background: msg.startsWith('✓') ? '#d1fae5' : '#fee2e2', color: msg.startsWith('✓') ? '#059669' : '#dc2626', padding: '12px 16px', borderRadius: 10, fontSize: 13, fontWeight: 600, marginBottom: 16 }}>
          {msg}
        </div>
      )}

      {/* Filter tabs */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 20 }}>
        {[['pending', '⏳ Pending'], ['approved', '✅ Approved'], ['rejected', '✕ Rejected']].map(([val, label]) => (
          <button key={val} onClick={() => setFilter(val)}
            style={{ padding: '8px 18px', background: filter === val ? '#1a1a2e' : '#fff', color: filter === val ? '#fff' : '#6b7280', border: filter === val ? 'none' : '1px solid #e8e0d0', borderRadius: 10, fontSize: 13, fontWeight: 500, cursor: 'pointer', fontFamily: 'inherit' }}>
            {label}
          </button>
        ))}
      </div>

      {/* Requests list */}
      {loading ? (
        <div style={{ textAlign: 'center', padding: 60, color: '#9ca3af' }}>Loading...</div>
      ) : requests.length ? (
        <div style={{ display: 'grid', gap: 14 }}>
          {requests.map(req => (
            <div key={req.id} style={{ background: '#fff', border: '1px solid #e8e0d0', borderRadius: 16, padding: 20 }}>
              <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
                {/* Book Info */}
                <div style={{ flex: 1, minWidth: 200 }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: '#9ca3af', textTransform: 'uppercase', marginBottom: 6 }}>📚 Book</div>
                  <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 2 }}>{req.title}</div>
                  <div style={{ fontSize: 12, color: '#9ca3af', marginBottom: 8 }}>{req.author}</div>
                  <span style={{ fontSize: 11, fontWeight: 600, padding: '3px 10px', borderRadius: 99, background: req.available_copies > 0 ? '#d1fae5' : '#fee2e2', color: req.available_copies > 0 ? '#059669' : '#dc2626' }}>
                    {req.available_copies} copies available
                  </span>
                </div>

                {/* Member Info */}
                <div style={{ flex: 1, minWidth: 200, background: '#f5f0e8', borderRadius: 12, padding: 14 }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: '#9ca3af', textTransform: 'uppercase', marginBottom: 8 }}>👤 Member Info</div>
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
                    {[
                      ['Name', req.member_name],
                      ['ID', req.member_code],
                      ['Type', req.account_type],
                      ['Department', req.department || '—'],
                      ['Batch', req.batch || '—'],
                      ['Mobile', req.mobile || '—'],
                      ['Email', req.member_email],
                    ].map(([label, value]) => (
                      <div key={label}>
                        <div style={{ fontSize: 10, color: '#9ca3af', fontWeight: 600 }}>{label}</div>
                        <div style={{ fontSize: 12, fontWeight: 600, color: '#1a1a2e', textTransform: 'capitalize' }}>{value}</div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Status & Actions */}
                <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'space-between', alignItems: 'flex-end', minWidth: 140 }}>
                  <div style={{ textAlign: 'right' }}>
                    <span style={{ fontSize: 11, fontWeight: 600, padding: '4px 12px', borderRadius: 99, background: req.status === 'pending' ? '#fef3c7' : req.status === 'approved' ? '#d1fae5' : '#fee2e2', color: req.status === 'pending' ? '#d97706' : req.status === 'approved' ? '#059669' : '#dc2626', textTransform: 'capitalize' }}>
                      {req.status}
                    </span>
                    <div style={{ fontSize: 11, color: '#9ca3af', marginTop: 6 }}>
                      {new Date(req.request_date).toLocaleDateString('en-GB')}
                    </div>
                    {req.reviewed_by_name && (
                      <div style={{ fontSize: 11, color: '#9ca3af', marginTop: 4 }}>By: {req.reviewed_by_name}</div>
                    )}
                    {req.reject_reason && (
                      <div style={{ fontSize: 11, color: '#dc2626', marginTop: 4, maxWidth: 160 }}>"{req.reject_reason}"</div>
                    )}
                  </div>

                  {req.status === 'pending' && (
                    <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
                      <button onClick={() => openApprove(req)}
                        style={{ padding: '8px 16px', background: '#059669', color: '#fff', border: 'none', borderRadius: 9, fontSize: 13, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit' }}>
                        ✓ Approve
                      </button>
                      <button onClick={() => { setRejectModal(req); setRejectReason(''); }}
                        style={{ padding: '8px 16px', background: '#fee2e2', color: '#dc2626', border: 'none', borderRadius: 9, fontSize: 13, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit' }}>
                        ✕ Reject
                      </button>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div style={{ textAlign: 'center', padding: 80, color: '#9ca3af' }}>
          <div style={{ fontSize: 52, marginBottom: 12 }}>📋</div>
          <p style={{ fontSize: 15, fontWeight: 600 }}>No {filter} requests</p>
        </div>
      )}

      {/* Approve Modal */}
      {approveModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(26,26,46,0.5)', backdropFilter: 'blur(4px)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
          <div style={{ background: '#fff', borderRadius: 20, padding: 28, width: '100%', maxWidth: 400 }}>
            <h2 style={{ fontFamily: "'Playfair Display',serif", fontSize: 20, fontWeight: 700, marginBottom: 6 }}>Approve Request</h2>
            <p style={{ fontSize: 13, color: '#6b7280', marginBottom: 20 }}>
              Issuing <strong>{approveModal.title}</strong> to <strong>{approveModal.member_name}</strong>
            </p>
            <div style={{ marginBottom: 20 }}>
              <label style={{ display: 'block', fontSize: 12, fontWeight: 600, color: '#6b7280', marginBottom: 6 }}>Due Date</label>
              <input style={inp} type="date" value={dueDate} onChange={e => setDueDate(e.target.value)} />
            </div>
            <div style={{ display: 'flex', gap: 10 }}>
              <button onClick={() => setApproveModal(null)} style={{ flex: 1, padding: 10, background: '#f5f0e8', border: 'none', borderRadius: 10, cursor: 'pointer', fontFamily: 'inherit', fontSize: 13 }}>Cancel</button>
              <button onClick={approve} style={{ flex: 1, padding: 10, background: '#059669', color: '#fff', border: 'none', borderRadius: 10, cursor: 'pointer', fontFamily: 'inherit', fontSize: 13, fontWeight: 600 }}>✓ Confirm Approve</button>
            </div>
          </div>
        </div>
      )}

      {/* Reject Modal */}
      {rejectModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(26,26,46,0.5)', backdropFilter: 'blur(4px)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
          <div style={{ background: '#fff', borderRadius: 20, padding: 28, width: '100%', maxWidth: 400 }}>
            <h2 style={{ fontFamily: "'Playfair Display',serif", fontSize: 20, fontWeight: 700, marginBottom: 6 }}>Reject Request</h2>
            <p style={{ fontSize: 13, color: '#6b7280', marginBottom: 20 }}>
              Rejecting <strong>{rejectModal.title}</strong> request from <strong>{rejectModal.member_name}</strong>
            </p>
            <div style={{ marginBottom: 20 }}>
              <label style={{ display: 'block', fontSize: 12, fontWeight: 600, color: '#6b7280', marginBottom: 6 }}>Reason (optional)</label>
              <textarea style={{ ...inp, minHeight: 80, resize: 'vertical' }} value={rejectReason} onChange={e => setRejectReason(e.target.value)} placeholder="e.g. Book reserved for another member..." />
            </div>
            <div style={{ display: 'flex', gap: 10 }}>
              <button onClick={() => setRejectModal(null)} style={{ flex: 1, padding: 10, background: '#f5f0e8', border: 'none', borderRadius: 10, cursor: 'pointer', fontFamily: 'inherit', fontSize: 13 }}>Cancel</button>
              <button onClick={reject} style={{ flex: 1, padding: 10, background: '#dc2626', color: '#fff', border: 'none', borderRadius: 10, cursor: 'pointer', fontFamily: 'inherit', fontSize: 13, fontWeight: 600 }}>✕ Confirm Reject</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
